import React, { useEffect, useMemo, useState } from 'react';
import api from '../../services/api';
import { toAbsoluteImageUrl } from '../../utils/imageUrl';

const formatCurrency = (value) =>
  new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' }).format(Number(value || 0));

const REFRESH_MS = 30000;

const CustomerDisplay = () => {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [now, setNow] = useState(new Date());

  const fetchProducts = async (isInitialLoad = false) => {
    try {
      if (isInitialLoad) {
        setLoading(true);
      }
      setError('');
      const res = await api.get('/products/customer-display');
      setProducts(Array.isArray(res.data) ? res.data : []);
    } catch {
      setError('Unable to load products for customer screen.');
    } finally {
      if (isInitialLoad) {
        setLoading(false);
      }
    }
  };

  useEffect(() => {
    fetchProducts(true);
    const refreshId = setInterval(() => fetchProducts(false), REFRESH_MS);
    const clockId = setInterval(() => setNow(new Date()), 1000);

    return () => {
      clearInterval(refreshId);
      clearInterval(clockId);
    };
  }, []);

  const inStockCount = useMemo(() => products.filter((p) => Number(p.stockQty) > 0).length, [products]);
  const lowStockCount = useMemo(
    () => products.filter((p) => Number(p.stockQty) > 0 && Number(p.stockQty) <= 5).length,
    [products],
  );

  return (
    <div className="min-h-screen text-white bg-[radial-gradient(circle_at_15%_20%,rgba(16,185,129,0.24),transparent_35%),radial-gradient(circle_at_90%_5%,rgba(59,130,246,0.22),transparent_32%),linear-gradient(135deg,#0f172a_0%,#111827_48%,#052e2b_100%)]">
      <header className="sticky top-0 z-20 px-6 py-5 border-b border-white/10 bg-slate-950/45 backdrop-blur-xl">
        <div className="flex items-center justify-between mx-auto max-w-screen-2xl">
          <div>
            <p className="text-[11px] font-bold uppercase tracking-[0.24em] text-emerald-300">Welcome</p>
            <h1 className="mt-1 text-2xl font-black tracking-tight sm:text-3xl">KH Mart Customer View</h1>
            <p className="text-sm text-emerald-100/85">Today deals, in-store pricing, and live stock status</p>
          </div>
          <div className="text-right">
            <p className="text-xl font-black tabular-nums">{now.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}</p>
            <p className="text-sm text-emerald-200/90">{now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
          </div>
        </div>
      </header>

      <main className="px-6 py-6 mx-auto max-w-screen-2xl">
        <div className="grid gap-4 mb-6 sm:grid-cols-2 lg:grid-cols-4">
          <div className="rounded-2xl border border-white/15 bg-white/[0.07] p-4 shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
            <p className="text-xs font-bold uppercase tracking-[0.14em] text-emerald-300">Products</p>
            <p className="mt-1 text-3xl font-black">{products.length}</p>
          </div>
          <div className="rounded-2xl border border-white/15 bg-white/[0.07] p-4 shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
            <p className="text-xs font-bold uppercase tracking-[0.14em] text-emerald-300">In Stock</p>
            <p className="mt-1 text-3xl font-black">{inStockCount}</p>
          </div>
          <div className="rounded-2xl border border-white/15 bg-white/[0.07] p-4 shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
            <p className="text-xs font-bold uppercase tracking-[0.14em] text-amber-200">Low Stock (1-5)</p>
            <p className="mt-1 text-3xl font-black text-amber-100">{lowStockCount}</p>
          </div>
          <div className="rounded-2xl border border-white/15 bg-white/[0.07] p-4 shadow-[0_12px_36px_rgba(2,6,23,0.35)]">
            <p className="text-xs font-bold uppercase tracking-[0.14em] text-sky-200">Auto Refresh</p>
            <p className="mt-1 text-3xl font-black">{Math.floor(REFRESH_MS / 1000)}s</p>
          </div>
        </div>

        {loading ? (
          <div className="py-16 text-center text-emerald-200">Loading customer display...</div>
        ) : error ? (
          <div className="rounded-2xl border border-red-300/30 bg-red-500/10 py-16 text-center text-red-200">{error}</div>
        ) : products.length === 0 ? (
          <div className="rounded-2xl border border-emerald-300/25 bg-emerald-500/10 py-16 text-center text-emerald-100">No active products available.</div>
        ) : (
          <div className="grid gap-5 sm:grid-cols-2 xl:grid-cols-3 2xl:grid-cols-4">
            {products.map((product) => (
              <div
                key={product.productId}
                className="group overflow-hidden rounded-2xl border border-white/15 bg-[linear-gradient(140deg,rgba(255,255,255,0.16),rgba(255,255,255,0.05))] p-4 shadow-[0_18px_38px_rgba(2,6,23,0.35)] transition duration-300 hover:-translate-y-1 hover:border-emerald-200/40"
              >
                <div className="mb-4 overflow-hidden rounded-xl bg-black/20">
                  {product.imageUrl ? (
                    <img
                      src={toAbsoluteImageUrl(product.imageUrl)}
                      alt={product.productName}
                      className="h-44 w-full object-cover transition duration-300 group-hover:scale-105"
                    />
                  ) : (
                    <div className="flex h-44 w-full items-center justify-center text-sm text-emerald-200">No Image</div>
                  )}
                </div>
                <h2 className="line-clamp-2 text-lg font-black tracking-tight">{product.productName}</h2>
                <div className="flex items-center justify-between mt-3">
                  <p className="text-2xl font-black text-emerald-300">{formatCurrency(product.sellingPrice)}</p>
                  <span className={`rounded-full px-2 py-1 text-xs font-bold ${Number(product.stockQty) > 0 ? 'bg-emerald-400/20 text-emerald-100' : 'bg-red-400/20 text-red-100'}`}>
                    {Number(product.stockQty) > 0 ? 'Available' : 'Out of Stock'}
                  </span>
                </div>
                <p className="mt-2 text-xs text-emerald-100/80">Stock: {Number(product.stockQty) || 0}</p>
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
};

export default CustomerDisplay;
